// src/components/MovieBanner.tsx
import { FC, ReactNode } from "react";
import { ChevronLeft } from "lucide-react";
import { useNavigate } from "react-router-dom";

interface MovieBannerProps {
  bannerUrl: string;
  title: string;
  metadata: string;
  children?: ReactNode; // Optional button group or anything else
}

const MovieBanner: FC<MovieBannerProps> = ({
  bannerUrl,
  title,
  metadata,
  children,
}) => {
  const navigate = useNavigate();

  return (
    <div className="banner" style={{ backgroundImage: `url(${bannerUrl})` }}>
      <button className="back-button" onClick={() => navigate(-1)}>
        <ChevronLeft size={20} /> Back
      </button>
      <div className="details-overlay">
        <h1 className="title">{title}</h1>
        <p className="metadata">{metadata}</p>
        {children && <div className="button-group">{children}</div>}
      </div>
    </div>
  );
};

export default MovieBanner;
